118	        {appName}
119	      </Link>
120	    ) : (
121	      <Link to={href}>{appName}</Link>
122	    );
123	
124	    return (
125	      <li key={`App_${namespace}_${appName}`} className={itemStyle}>
126	        <div className={iconStyle}>
127	          <PFBadge badge={PFBadges.App} position={TooltipPosition.top} />
128	        </div>
129	
130	        <span>{link}</span>
131	      </li>
132	    );
