135	  const renderServiceItem = (namespace: string, serviceName: string): React.ReactNode => {
136	    let href = `/namespaces/${namespace}/services/${serviceName}`;
137	
138	    if (props.cluster && isMultiCluster) {
139	      href = `${href}?clusterName=${props.cluster}`;
140	    }
141	
142	    const link = isParentKiosk(props.kiosk) ? (
143	      <Link
144	        to=""
145	        onClick={() => {
146	          kioskContextMenuAction(href);
147	        }}
148	      >
149	        {serviceName}
150	      </Link>
151	    ) : (
152	      <Link to={href}>{serviceName}</Link>
153	    );
154	
155	    return (
156	      <li key={`Service_${serviceName}`} className={itemStyle}>
157	        <div className={iconStyle}>
158	          <PFBadge badge={PFBadges.Service} position={TooltipPosition.top} />
159	        </div>
160	
161	        <span>{link}</span>
162	      </li>
163	    );
