166	  const renderEmptyItem = (type: string): React.ReactNode => {
167	    const message = `No ${type} found`;
168	
169	    return <div> {message} </div>;
170	  };
171	
172	  const appList = (): React.ReactNode => {
173	    let applicationList: React.ReactNode = <></>;
174	
175	    if (props.apps !== undefined) {
176	      applicationList =
177	        props.apps && props.apps.length > 0
178	          ? props.apps
179	              .filter(name => {
180	                if (name === undefined) {
181	                  return null;
182	                }
183	
184	                return name;
185	              })
186	              .map(name => renderAppItem(props.namespace, name))
187	          : renderEmptyItem('applications');
