238	
239	    if (props.workloads && props.workloads.length > 0) {
240	      for (let i = 0; i < props.workloads.length; i++) {
241	        const hWorkload = sub.text.substring(0, sub.text.indexOf(':'));
242	
243	        if (hWorkload === props.workloads[i].workloadName) {
244	          workload = props.workloads[i];
245	          break;
246	        }
247	      }
248	    }
249	
250	    if (workload) {
251	      let href = `/namespaces/${props.namespace}/workloads/${workload.workloadName}`;
