326	  const renderWorkloadStatus = (): React.ReactNode => {
327	    if (props.health) {
328	      const item = props.health.getWorkloadStatus();
329	
330	      if (item) {
331	        item.children?.sort((i1, i2) => (i1.text < i2.text ? -1 : 1));
332	        return (
333	          <div>
334	            {item.text}
335	
336	            {item.children && (
337	              <ul id="workload-list" style={{ listStyleType: 'none' }}>
338	                {item.children.map((sub, subIdx) => {
339	                  return (
340	                    <li key={subIdx} className={itemStyle}>
341	                      {renderWorkloadHealthItem(sub)}
342	                    </li>
343	                  );
344	                })}
345	              </ul>
346	            )}
347	          </div>
348	        );
349	      } else {
350	        return (
351	          <div>
352	            <ul id="workload-list" style={{ listStyleType: 'none' }}>
353	              {props.workloads
354	                ? props.workloads.map((wkd, subIdx) => {
355	                    return (
356	                      <li key={subIdx} className={itemStyle}>
357	                        {renderWorkloadItem(wkd)}
358	                      </li>
359	                    );
360	                  })
361	                : undefined}
362	            </ul>
363	          </div>
364	        );
365	      }
366	    }
367	    return undefined;
368	  };
369	
370	  const workloadSummary = (): React.ReactNode => {
371	    return <div className={resourceListStyle}>{renderWorkloadStatus()}</div>;
372	  };
373	
374	  const serviceList = (): React.ReactNode => {
375	    let serviceList: React.ReactNode = <></>;
376	
377	    if (serviceList !== undefined) {
378	      serviceList =
379	        props.services && props.services.length > 0
380	          ? props.services.map(name => renderServiceItem(props.namespace, name))
381	          : renderEmptyItem('services');
382	    }
383	
384	    return [
385	      <div key="service-list" className={resourceListStyle}>
386	        <ul id="service-list" style={{ listStyleType: 'none' }}>
387	          {serviceList}
388	        </ul>
389	      </div>
390	    ];
391	  };
392	
393	  props.apps?.sort((a1: string, a2: string) => (a1 < a2 ? -1 : 1));
394	  props.services?.sort((s1: string, s2: string) => (s1 < s2 ? -1 : 1));
395	  props.waypointWorkloads?.sort((w1: WorkloadInfo, w2: WorkloadInfo) => (w1.name < w2.name ? -1 : 1));
396	  props.workloads?.sort((w1: AppWorkload, w2: AppWorkload) => (w1.workloadName < w2.workloadName ? -1 : 1));
397	
398	  return (
399	    <div className={containerStyle}>
400	      {props.apps !== undefined && appList()}
401	      {props.workloads !== undefined && workloadSummary()}
402	      {props.services !== undefined && serviceList()}
403	      {props.waypointWorkloads && renderWaypoints()}
404	      {props.health && renderTrafficStatus(props.health)}
405	    </div>
406	  );
407	};
408	
409	const mapStateToProps = (state: KialiAppState): ReduxProps => ({
410	  kiosk: state.globalState.kiosk
411	});
412	
413	export const DetailDescription = connect(mapStateToProps)(DetailDescriptionComponent);

